1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	type Item = { type: string };
13	type Step = { op: "quote"; items: Item[] };
14	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
15	
16	const basePremiumOf = (item: Item): number => BASE_PREMIUM[item.type];
17	
18	const COMPONENT_TYPES = new Set(["rune"]);
19	const BLOCK_SIZE = 3;
20	const BLOCK_BASE_PREMIUM = 60;
21	
22	const policyBaseOf = (items: Item[]): number => {
23	  const components = items.filter((it) => COMPONENT_TYPES.has(it.type));
24	  const mainItems = items.filter((it) => !COMPONENT_TYPES.has(it.type));
25	  const mainBase = mainItems.reduce((sum, item) => sum + basePremiumOf(item), 0);
26	  if (components.length === BLOCK_SIZE) {
27	    return mainBase + BLOCK_BASE_PREMIUM;
28	  }
29	  const componentBase = components.reduce((sum, item) => sum + basePremiumOf(item), 0);
30	  return mainBase + componentBase;
31	};
32	
33	const firstInsuranceSurchargeOf = (policyBase: number): number =>
34	  policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
35	
36	const quotePremium = (items: Item[]): number => {
37	  const policyBase = policyBaseOf(items);
38	  return policyBase + firstInsuranceSurchargeOf(policyBase) + PROCESSING_FEE;
39	};
40	
41	export const processScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
42	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
43	  return { results };
44	};
